class Solution:
    def numBusesToDestination(self, routes, source, target):
        from collections import deque
        if source == target:
            return 0
        # Independent: BFS over stops, expanding via every unused route at a stop.
        stop_to_buses = {}
        for b, route in enumerate(routes):
            for s in route:
                stop_to_buses.setdefault(s, []).append(b)
        visited_stops = {source}
        used_buses = set()
        q = deque([(source, 0)])
        while q:
            stop, buses = q.popleft()
            for b in stop_to_buses.get(stop, []):
                if b in used_buses:
                    continue
                used_buses.add(b)
                for ns in routes[b]:
                    if ns == target:
                        return buses + 1
                    if ns not in visited_stops:
                        visited_stops.add(ns)
                        q.append((ns, buses + 1))
        return -1

