class Solution:
    def numBusesToDestination(self, routes, source, target):
        from collections import deque, defaultdict
        if source == target:
            return 0
        stop_to_buses = defaultdict(list)
        for b, route in enumerate(routes):
            for s in route:
                stop_to_buses[s].append(b)
        route_sets = [set(r) for r in routes]
        visited_bus = set()
        q = deque()
        for b in stop_to_buses[source]:
            visited_bus.add(b)
            q.append((b, 1))
        while q:
            bus, count = q.popleft()
            if target in route_sets[bus]:
                return count
            for s in routes[bus]:
                for nb in stop_to_buses[s]:
                    if nb not in visited_bus:
                        visited_bus.add(nb)
                        q.append((nb, count + 1))
        return -1

