var numBusesToDestination = function(routes, source, target) {
    if (source === target) return 0;
    const stopToBuses = new Map();
    for (let b = 0; b < routes.length; b++) {
        for (const s of routes[b]) {
            if (!stopToBuses.has(s)) stopToBuses.set(s, []);
            stopToBuses.get(s).push(b);
        }
    }
    const routeSets = routes.map(r => new Set(r));
    const visited = new Set();
    const q = [];
    for (const b of (stopToBuses.get(source) || [])) {
        visited.add(b);
        q.push([b, 1]);
    }
    let head = 0;
    while (head < q.length) {
        const [bus, count] = q[head++];
        if (routeSets[bus].has(target)) return count;
        for (const s of routes[bus]) {
            for (const nb of (stopToBuses.get(s) || [])) {
                if (!visited.has(nb)) {
                    visited.add(nb);
                    q.push([nb, count + 1]);
                }
            }
        }
    }
    return -1;
};
